-- Outreach email templates — admin-managed templates for organizer outreach campaigns.
-- Used in /admin/organizers/[id]/edit "✉ Покани" modal to pre-fill subject + body.

CREATE TABLE IF NOT EXISTS outreach_email_templates (
  id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  name        text        NOT NULL,
  subject     text        NOT NULL DEFAULT '',
  body        text        NOT NULL DEFAULT '',
  sort_order  integer     NOT NULL DEFAULT 0,
  created_at  timestamptz NOT NULL DEFAULT now(),
  updated_at  timestamptz NOT NULL DEFAULT now()
);

-- Only admins (service role) access this table.
ALTER TABLE outreach_email_templates ENABLE ROW LEVEL SECURITY;

CREATE POLICY "no_public_access" ON outreach_email_templates
  FOR ALL USING (false);

-- Seed with three starter templates
INSERT INTO outreach_email_templates (name, subject, body, sort_order) VALUES (
  'Народни читалища',
  'Festivo.bg — фестивалите на вашето читалище вече са в каталога',
  E'Здравейте,\n\nКазвам се Борислав и съм основателят на Festivo.bg — новата платформа, създадена специално, за да помага на народни читалища, общини и кметства да достигнат до повече хора с фестивалите, които организират.\n\nФестивалите на {{organizerName}} вече са в каталога:\n\n{{festivalList}}\n\nВсеки месец хиляди хора разглеждат Festivo.bg в търсене на местни фестивали, събори и празници. Когато потребителите намерят интересно събитие, го добавят в „Моят план" — лична колекция с предстоящи фестивали, за която получават напомняния по имейл и в мобилното приложение. Така вашите фестивали достигат до точните хора в точното време.\n\nПоканваме ви да заявите профила си на:\n{{claimUrl}}\n\nСлед като заявите, ще можете да:\n• Редактирате описания, снимки и програма\n• Виждате колко хора са добавили вашия фестивал в плана си\n• Добавяте нови фестивали директно\n\n🎁 За 2026 г. предлагаме безплатен VIP Организатор статус — специално за малки и местни организатори като вас. VIP означава по-добро класиране в резултатите и отличителен знак на вашия профил, без никаква такса.\n\nОтнема 2 минути. Ако имате въпроси, отговорете директно на този имейл.\n\nС уважение,\nБорислав\nFestivo.bg | b.yakov@festivo.bg',
  10
), (
  'Общини и кметства',
  'Festivo.bg — местните ви фестивали вече са видими за цяла България',
  E'Здравейте,\n\nКазвам се Борислав и съм основателят на Festivo.bg — каталогът на фестивалите в България.\n\nПлатформата е създадена с мисълта да помага на общини и кметства да популяризират местните си фестивали, събори и традиционни празници пред по-широка аудитория.\n\nФестивалите на {{organizerName}} вече са в каталога:\n\n{{festivalList}}\n\nПотребителите на Festivo.bg добавят любимите си фестивали в „Моят план" и получават напомняния преди началото — така местните Ви събития достигат до хора от цяла България, не само от региона.\n\nПоканваме Ви да заявите профила си безплатно:\n{{claimUrl}}\n\n🎁 Безплатен VIP статус за 2026 г. — специално за общини, кметства и местни организатори. По-добро класиране в каталога и отличителен знак на профила, без никаква такса.\n\nС уважение,\nБорислав\nFestivo.bg | b.yakov@festivo.bg',
